import React, { useEffect, useState } from "react";

export default function ProductModal({ open, mode, initialProduct, onClose, onSubmit }) {
    const [name, setName] = useState("");
    const [category, setCategory] = useState("");
    const [description, setDescription] = useState("");
    const [price, setPrice] = useState("");
    const [stock, setStock] = useState("");
    const [image, setImage] = useState("");
    const [rating, setRating] = useState("");

    useEffect(() => {
        if (!open) return;
        setName(initialProduct?.name ?? "");
        setCategory(initialProduct?.category ?? "");
        setDescription(initialProduct?.description ?? "");
        setPrice(initialProduct?.price != null ? String(initialProduct.price) : "");
        setStock(initialProduct?.stock != null ? String(initialProduct.stock) : "");
        setImage(initialProduct?.image ?? "");
        setRating(initialProduct?.rating != null ? String(initialProduct.rating) : "");
    }, [open, initialProduct]);

    if (!open) return null;

    const title = mode === "edit" ? "Редактирование товара" : "Добавление товара";

    const handleSubmit = (e) => {
        e.preventDefault();

        const trimmedName = name.trim();
        const trimmedCategory = category.trim();
        const trimmedDescription = description.trim();
        const trimmedImage = image.trim();
        const parsedPrice = Number(price);
        const parsedStock = Number(stock);
        const parsedRating = rating ? Number(rating) : 0;

        if (!trimmedName) {
            alert("Введите название товара");
            return;
        }
        if (!trimmedCategory) {
            alert("Введите категорию товара");
            return;
        }
        if (!Number.isFinite(parsedPrice) || parsedPrice < 0) {
            alert("Введите корректную цену");
            return;
        }
        if (!Number.isInteger(parsedStock) || parsedStock < 0) {
            alert("Введите корректное количество на складе");
            return;
        }
        if (parsedRating < 0 || parsedRating > 5) {
            alert("Рейтинг должен быть от 0 до 5");
            return;
        }

        onSubmit({
            id: initialProduct?.id,
            name: trimmedName,
            category: trimmedCategory,
            description: trimmedDescription,
            price: parsedPrice,
            stock: parsedStock,
            image: trimmedImage || 'https://images.unsplash.com/photo-1581235720704-06d3acfcb36f?w=300&h=300&fit=crop',
            rating: parsedRating,
        });
    };

    return (
        <div className="backdrop" onMouseDown={onClose}>
            <div className="modal" onMouseDown={(e) => e.stopPropagation()} role="dialog" aria-modal="true">
                <div className="modal__header">
                    <div className="modal__title">{title}</div>
                    <button className="iconBtn" onClick={onClose} aria-label="Закрыть">
                        ✕
                    </button>
                </div>

                <form className="form" onSubmit={handleSubmit}>
                    <label className="label">
                        Название товара *
                        <input
                            className="input"
                            value={name}
                            onChange={(e) => setName(e.target.value)}
                            placeholder="Например, Холодильник LG"
                            autoFocus
                            required
                        />
                    </label>

                    <label className="label">
                        Категория *
                        <input
                            className="input"
                            value={category}
                            onChange={(e) => setCategory(e.target.value)}
                            placeholder="Например, Бытовая техника"
                            required
                        />
                    </label>

                    <label className="label">
                        Описание
                        <textarea
                            className="input textarea"
                            value={description}
                            onChange={(e) => setDescription(e.target.value)}
                            placeholder="Краткое описание товара"
                            rows="2"
                        />
                    </label>

                    <div className="form__row">
                        <label className="label">
                            Цена (₽) *
                            <input
                                className="input"
                                value={price}
                                onChange={(e) => setPrice(e.target.value)}
                                placeholder="35000"
                                inputMode="numeric"
                                required
                            />
                        </label>

                        <label className="label">
                            На складе (шт.) *
                            <input
                                className="input"
                                value={stock}
                                onChange={(e) => setStock(e.target.value)}
                                placeholder="10"
                                inputMode="numeric"
                                required
                            />
                        </label>
                    </div>

                    <div className="form__row">
                        <label className="label">
                            URL фото
                            <input
                                className="input"
                                value={image}
                                onChange={(e) => setImage(e.target.value)}
                                placeholder="https://...jpg"
                            />
                        </label>

                        <label className="label">
                            Рейтинг (0-5)
                            <input
                                className="input"
                                value={rating}
                                onChange={(e) => setRating(e.target.value)}
                                placeholder="4.5"
                                inputMode="decimal"
                                step="0.1"
                                min="0"
                                max="5"
                            />
                        </label>
                    </div>

                    {image && (
                        <div className="image-preview">
                            <img src={image} alt="Preview" style={{ width: '100%', maxHeight: '100px', objectFit: 'cover', borderRadius: '8px' }} />
                        </div>
                    )}

                    <div className="modal__footer">
                        <button type="button" className="btn" onClick={onClose}>
                            Отмена
                        </button>
                        <button type="submit" className="btn btn--primary">
                            {mode === "edit" ? "Сохранить" : "Добавить"}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
}
